function SecurityPage() {
  return (
    <div style={{flex:1, display:"flex", flexDirection:"column", alignItems:"center"}}>


      <header style={{display:"flex",flexDirection:"column", borderBottom:"1px solid #ccc", alignItems:"center", justifyContent:"center", width:"100%"}}>
        <h2 style={{fontWeight:"500"}}>Security</h2>
        <span style={{marginBottom:"1rem", fontWeight:"100"}}>Защити свой профиль</span>
      </header>

      <div>

        
        <div className="Basics" style={{display:"flex", flexDirection:"column", marginTop:"1.5rem" }}>
          <span>Basics:</span>
          <InputForm TextPlaceholder={"Name"} zstyle={"mini-input"}/>
          <InputForm TextPlaceholder={"LastName"} zstyle={"mini-input"}/>
          <InputForm TextPlaceholder={"Role"} zstyle={"mini-input"}/>
        </div>
      </div>


    </div>
  );
}

export default SecurityPage;
